/**
 * Bitstring Status List Checker
 *
 * Implements W3C Bitstring Status List (2025) checking for VC revocation.
 * https://www.w3.org/TR/vc-bitstring-status-list/
 *
 * The status list is a compressed bitstring where each credential's
 * revocation/suspension status is represented by a single bit at a
 * specific index.
 *
 * Cache pattern matches JWKS/DID caches: DB-backed with configurable TTL.
 */

import { gunzipSync } from "node:zlib";
import { getPool } from "../db/pool.js";

/** Cache TTL for status lists (seconds). */
function cacheTtlSeconds() {
  return parseInt(process.env.STATUS_LIST_CACHE_TTL_SECONDS || "60", 10);
}

/**
 * Check credential status against a Bitstring Status List.
 *
 * @param {object} credentialStatus - The credentialStatus object from the VC
 *   { type: "BitstringStatusListEntry", statusPurpose: "revocation",
 *     statusListIndex: "42", statusListCredential: "https://..." }
 * @returns {{ revoked: boolean, suspended: boolean, error?: string }}
 */
export async function checkBitstringStatus(credentialStatus) {
  if (!credentialStatus) {
    // No status entry — no revocation mechanism, treated as valid
    return { revoked: false, suspended: false };
  }

  const type = credentialStatus.type || credentialStatus.statusType;
  if (type !== "BitstringStatusListEntry" && type !== "StatusList2021Entry") {
    return { revoked: false, suspended: false, error: `Unknown status type: ${type}` };
  }

  const statusListUrl = credentialStatus.statusListCredential;
  const statusIndex = parseInt(credentialStatus.statusListIndex, 10);
  const purpose = credentialStatus.statusPurpose || "revocation";

  if (!statusListUrl || isNaN(statusIndex) || statusIndex < 0) {
    return { revoked: false, suspended: false, error: "Invalid status list entry" };
  }

  try {
    const encodedList = await fetchStatusList(statusListUrl);
    if (!encodedList) {
      // Cannot fetch status list — fail-closed for revocation
      return {
        revoked: purpose === "revocation",
        suspended: purpose === "suspension",
        error: "Status list unavailable — fail-closed",
      };
    }

    const bitValue = decodeBitAtIndex(encodedList, statusIndex);
    if (bitValue === null) {
      return {
        revoked: purpose === "revocation",
        suspended: purpose === "suspension",
        error: "Status index out of range — fail-closed",
      };
    }

    // bit=1 means the status IS set (revoked/suspended)
    return {
      revoked: purpose === "revocation" && bitValue === 1,
      suspended: purpose === "suspension" && bitValue === 1,
    };
  } catch (err) {
    // Network/parse error — fail-closed
    return {
      revoked: purpose === "revocation",
      suspended: purpose === "suspension",
      error: `Status check failed: ${err.message} — fail-closed`,
    };
  }
}

/**
 * Fetch a status list credential and extract the encoded bitstring.
 * Uses DB cache with TTL.
 *
 * @param {string} statusListUrl
 * @returns {string|null} The base64url-encoded compressed bitstring, or null on failure.
 */
async function fetchStatusList(statusListUrl) {
  const pool = getPool();

  // Check cache
  const { rows } = await pool.query(
    `SELECT encoded_list FROM portauth_status_list_cache
     WHERE status_list_url = $1 AND expires_at > NOW()`,
    [statusListUrl]
  );

  if (rows.length > 0) {
    return rows[0].encoded_list;
  }

  // Fetch from network with strict timeout
  const timeoutMs = parseInt(process.env.STATUS_LIST_FETCH_TIMEOUT_MS || "5000", 10);
  const resp = await fetch(statusListUrl, {
    signal: AbortSignal.timeout(timeoutMs),
    headers: { Accept: "application/vc+jwt, application/json" },
  });

  if (!resp.ok) {
    console.warn(`Status list fetch failed: ${statusListUrl} → ${resp.status}`);
    return null;
  }

  const contentType = resp.headers.get("content-type") || "";
  let encodedList;

  if (contentType.includes("application/vc+jwt")) {
    // Status list credential as JWT — decode payload
    const jwt = await resp.text();
    const parts = jwt.split(".");
    if (parts.length !== 3) return null;
    const payload = JSON.parse(Buffer.from(parts[1], "base64url").toString());
    encodedList = extractEncodedListFromPayload(payload);
  } else {
    // JSON response — could be VC JSON or plain status list
    const body = await resp.json();
    encodedList = extractEncodedListFromPayload(body);
  }

  if (!encodedList) {
    console.warn(`No encodedList found in status list credential from ${statusListUrl}`);
    return null;
  }

  // Cache
  const ttl = cacheTtlSeconds();
  const expiresAt = new Date(Date.now() + ttl * 1000);
  await pool.query(
    `INSERT INTO portauth_status_list_cache (status_list_url, encoded_list, fetched_at, expires_at)
     VALUES ($1, $2, NOW(), $3)
     ON CONFLICT (status_list_url) DO UPDATE SET
       encoded_list = EXCLUDED.encoded_list,
       fetched_at = NOW(),
       expires_at = EXCLUDED.expires_at`,
    [statusListUrl, encodedList, expiresAt]
  );

  return encodedList;
}

/**
 * Extract the encodedList from a status list credential payload.
 * Handles both W3C VCDM 2.0 shape and flat shapes.
 */
function extractEncodedListFromPayload(payload) {
  // VCDM 2.0: credentialSubject.encodedList
  if (payload.credentialSubject?.encodedList) {
    return payload.credentialSubject.encodedList;
  }
  // JWT-VC: vc.credentialSubject.encodedList
  if (payload.vc?.credentialSubject?.encodedList) {
    return payload.vc.credentialSubject.encodedList;
  }
  // Flat: encodedList at top level
  if (payload.encodedList) {
    return payload.encodedList;
  }
  return null;
}

/**
 * Decode a specific bit from a base64url-encoded, GZIP-compressed bitstring.
 *
 * Per the W3C Bitstring Status List spec:
 * 1. base64url-decode the encodedList
 * 2. GZIP-decompress the result
 * 3. Read the bit at the specified index
 *
 * @param {string} encodedList - base64url-encoded, GZIP-compressed bitstring
 * @param {number} index - 0-based bit index
 * @returns {number|null} 0 or 1, or null if index is out of range
 */
function decodeBitAtIndex(encodedList, index) {
  try {
    // Step 1: base64url decode
    const compressed = Buffer.from(encodedList, "base64url");

    // Step 2: GZIP decompress
    const bitstring = gunzipSync(compressed);

    // Step 3: Read bit at index
    const byteIndex = Math.floor(index / 8);
    const bitIndex = 7 - (index % 8); // MSB first within each byte

    if (byteIndex >= bitstring.length) {
      return null; // out of range
    }

    return (bitstring[byteIndex] >> bitIndex) & 1;
  } catch (err) {
    console.warn(`Failed to decode bitstring status list: ${err.message}`);
    return null;
  }
}

/**
 * Clear the status list cache (for testing).
 */
export async function clearStatusListCache() {
  const pool = getPool();
  await pool.query(`DELETE FROM portauth_status_list_cache`);
}
